        /// <summary>
        ///  Closed due to fencing.
        /// </summary>
        SLATEDB_CLOSE_REASON_FENCED = 2,
        /// <summary>
        ///  Closed due to background panic.
        /// </summary>
        SLATEDB_CLOSE_REASON_PANIC = 3,
        /// <summary>
